// Fan the run out to one item per lane, tagged with the current ISO week.
// Lanes are env-driven so a NEW lane needs zero workflow edits (ecosystem
// CLAUDE.md: lane N+1 costs a fraction of lane N) — set TOWER_BRIEF_LANES to a
// comma-separated list of lane slugs (e.g. "machinery,interiors,provisions").
const raw = ($env.TOWER_BRIEF_LANES || '').trim();
if (!raw) {
  throw new Error('TOWER_BRIEF_LANES env var is empty — set a comma-separated list of lane slugs.');
}
const lanes = raw.split(',').map((s) => s.trim()).filter(Boolean);

// ISO-8601 week string, e.g. 2026-W27.
const now = new Date();
const d = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()));
const dayNum = d.getUTCDay() === 0 ? 7 : d.getUTCDay();
d.setUTCDate(d.getUTCDate() + 4 - dayNum);
const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
const weekNo = Math.ceil(((d - yearStart) / 86400000 + 1) / 7);
const week = `${d.getUTCFullYear()}-W${String(weekNo).padStart(2, '0')}`;

return lanes.map((lane) => ({ json: { lane, week } }));
